template<typename T, int N>
__global__ void scan_without_bank_conflicts(const T* in, T* out, int64_t num_blocks)
{
  constexpr int PADDED = N + ((N - 1) >> LOG_MEM_BANKS);
  __shared__ T temp[PADDED];
  int thid = (int)threadIdx.x;

