  cudaFree(d_a);
  cudaFree(d_b);
  free(a);
  free(b);
  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <chrono>
#include <cuda_runtime.h>

#define RADIUS 7
#define BLOCK_SIZE 256

__global__ void stencil_kernel(const int* a, int* b, int length) {
  int block_base = blockIdx.x * BLOCK_SIZE;
  int j = threadIdx.x;

  __shared__ int temp[BLOCK_SIZE + 2 * RADIUS];

  int gindex = block_base + j;
  temp[j + RADIUS] = a[gindex];

  if (j < RADIUS) {
    temp[j] = (gindex < RADIUS) ? 0 : a[gindex - RADIUS];
    temp[j + RADIUS + BLOCK_SIZE] = a[gindex + BLOCK_SIZE];
  }

  __syncthreads();

  int result = 0;
  #pragma unroll
  for (int offset = -RADIUS; offset <= RADIUS; offset++) {
    result += temp[j + RADIUS + offset];
  }
  b[block_base + j] = result;
}

int main(int argc, char* argv[]) {
  if (argc != 3) {
    printf("Usage: %s <length> <repeat>\n", argv[0]);
    printf("length is a multiple of %d\n", BLOCK_SIZE);
    return 1;
  }
  const int length = atoi(argv[1]);
  const int repeat = atoi(argv[2]);

  int size = length;
  int pad_size = (length + RADIUS);

  int* a = (int*)malloc(pad_size * sizeof(int));
  int* b = (int*)malloc(size * sizeof(int));

  for (int i = 0; i < length + RADIUS; i++) a[i] = i;

  int* d_a = nullptr;
  int* d_b = nullptr;
  cudaMalloc((void**)&d_a, pad_size * sizeof(int));
  cudaMalloc((void**)&d_b, size * sizeof(int));

  dim3 block(BLOCK_SIZE);
  dim3 grid(length / BLOCK_SIZE);

  auto start = std::chrono::steady_clock::now();

  for (int i = 0; i < repeat; i++) {
    cudaMemcpy(d_a, a, pad_size * sizeof(int), cudaMemcpyHostToDevice);
    stencil_kernel<<<grid, block>>>(d_a, d_b, length);
    cudaMemcpy(b, d_b, size * sizeof(int), cudaMemcpyDeviceToHost);
  }

  cudaDeviceSynchronize();

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  printf("Average kernel execution time: %f (s)\n", (time * 1e-9f) / repeat);

  bool ok = true;
  for (int i = 0; i < 2 * RADIUS; i++) {
    int s = 0;
    for (int j = i; j <= i + 2 * RADIUS; j++)
      s += j < RADIUS ? 0 : (a[j] - RADIUS);
    if (s != b[i]) {
      printf("Error at %d: %d (host) != %d (device)\n", i, s, b[i]);
      ok = false;
      break;
    }
  }

  for (int i = 2 * RADIUS; i < length; i++) {
    int s = 0;
    for (int j = i - RADIUS; j <= i + RADIUS; j++)
      s += a[j];
    if (s != b[i]) {
      printf("Error at %d: %d (host) != %d (device)\n", i, s, b[i]);
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");

  cudaFree(d_a);
  cudaFree(d_b);
  free(a);
  free(b);
  return 0;
}
